import { PROVIDER_DISPLAY } from "@repo/app-providers/client";
import { Button } from "@repo/ui/components/ui/button";
import { Separator } from "@repo/ui/components/ui/separator";
import { JsonLd } from "@vendor/seo/json-ld";
import type { Metadata, Route } from "next";
import Image from "next/image";
import { notFound } from "next/navigation";
import { mdxComponents } from "~/app/(app)/(content)/_lib/mdx-components";
import {
  getIntegrationPage,
  getIntegrationPages,
} from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import { getProviderIcon } from "~/lib/get-provider-icon";
import { emitIntegrationSeo } from "~/lib/seo-bundle";
import type { IntegrationUrl } from "~/lib/url-types";
import { STATUS_LABEL } from "../_components/integration-labels";
import { IntegrationSidebar } from "../_components/integration-sidebar";

export const dynamic = "force-static";

interface Props {
  params: Promise<{ slug: string }>;
}

export function generateStaticParams() {
  return getIntegrationPages().map((page) => ({ slug: page.slugs[0] }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const page = getIntegrationPage([slug]);
  if (!page) {
    return {};
  }
  const url = `https://lightfast.ai/integrations/${slug}` as IntegrationUrl;
  const { metadata } = emitIntegrationSeo(page.data, url);
  return metadata;
}

export default async function IntegrationDetailPage({ params }: Props) {
  const { slug } = await params;
  const page = getIntegrationPage([slug]);
  if (!page) {
    notFound();
  }

  const url = `https://lightfast.ai/integrations/${slug}` as IntegrationUrl;
  const { jsonLd } = emitIntegrationSeo(page.data, url);
  const MDXContent = page.data.body;

  const {
    title,
    tagline,
    providerId,
    status: mdxStatus,
    category,
    featuredImage,
    docsUrl,
  } = page.data;

  const providerComingSoon =
    providerId && "comingSoon" in PROVIDER_DISPLAY[providerId]
      ? PROVIDER_DISPLAY[providerId].comingSoon
      : false;
  const derivedStatus: "live" | "beta" | "coming-soon" =
    mdxStatus ?? (providerComingSoon ? "coming-soon" : "live");
  const Icon = providerId ? getProviderIcon(providerId) : undefined;

  return (
    <>
      <JsonLd code={jsonLd} />
      <article className="space-y-8">
        <p className="text-muted-foreground text-sm">
          <Button
            asChild
            className="h-auto p-0 text-muted-foreground text-sm hover:text-foreground"
            variant="link"
          >
            <NavLink href="/integrations">Integrations</NavLink>
          </Button>
          {" / "}
          {title}
          {derivedStatus !== "live" && (
            <>
              {" · "}
              {STATUS_LABEL[derivedStatus]}
            </>
          )}
        </p>

        <p className="max-w-2xl text-foreground text-lg leading-relaxed">
          {tagline}
        </p>

        <Separator className="bg-border/50" />

        <div className="grid grid-cols-1 gap-16 lg:grid-cols-[minmax(0,1fr)_280px]">
          <div className="min-w-0 space-y-8">
            {featuredImage && (
              <div className="relative aspect-16/9 overflow-hidden">
                <Image
                  alt={title}
                  className="h-full w-full object-cover"
                  fill
                  priority
                  src={featuredImage}
                />
              </div>
            )}
            <div className="max-w-none">
              <MDXContent components={mdxComponents} />
            </div>
          </div>

          <IntegrationSidebar
            category={category}
            docsUrl={docsUrl}
            icon={Icon}
            status={derivedStatus}
            title={title}
          />
        </div>

        {(() => {
          const related = getIntegrationPages().filter(
            (p) => p.slugs[0] !== slug
          );
          if (related.length === 0) {
            return null;
          }
          return (
            <section className="pt-16">
              <h2 className="mb-6 font-medium font-pp text-xl">
                Other integrations
              </h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {related.map((p) => {
                  const rSlug = p.slugs[0] ?? "";
                  const RIcon = p.data.providerId
                    ? getProviderIcon(p.data.providerId)
                    : undefined;
                  return (
                    <NavLink
                      className="group flex h-[200px] flex-col justify-between gap-6 overflow-hidden rounded-md bg-accent/40 p-6 transition-colors hover:bg-accent"
                      href={`/integrations/${rSlug}` as Route}
                      key={rSlug}
                      prefetch
                    >
                      {RIcon && (
                        <RIcon aria-hidden className="size-5 text-foreground" />
                      )}
                      <div className="flex flex-col gap-3">
                        <h3 className="font-medium font-pp text-foreground text-xl">
                          {p.data.title}
                        </h3>
                        <p className="line-clamp-2 text-muted-foreground text-sm leading-relaxed">
                          {p.data.tagline}
                        </p>
                      </div>
                    </NavLink>
                  );
                })}
              </div>
            </section>
          );
        })()}
      </article>
    </>
  );
}

import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import type { Metadata, Route } from "next";
import { getIntegrationPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";
import { getProviderIcon } from "~/lib/get-provider-icon";
import { McpBentoSection } from "./_components/mcp-bento";
import { UpcomingIntegrationsList } from "./_components/upcoming-integrations-list";

export const dynamic = "force-static";

const PAGE_TITLE = "Integrations";
const PAGE_DESCRIPTION =
  "Connect Lightfast to the tools your engineering org runs on. GitHub, Vercel, Linear today — Sentry, PagerDuty, Stripe, Clerk, and 30+ more on the roadmap.";
const PAGE_URL = "https://lightfast.ai/integrations";
const FAQ = [
  {
    question: "What integrations does Lightfast support today?",
    answer:
      "GitHub, Vercel, and Linear are live. Each ingests events via OAuth and webhooks in real-time — pull requests, deploys, issues, and more.",
  },
  {
    question: "What's on the roadmap?",
    answer:
      "37 planned integrations spanning error tracking (Sentry, Datadog), incident response (PagerDuty, incident.io), billing (Stripe), auth (Clerk, WorkOS), product analytics (PostHog, Mixpanel, Amplitude), support (Intercom, Plain), CRM (HubSpot, Attio), and more. See the full list on this page.",
  },
  {
    question: "Can I request an integration or vote on priority?",
    answer:
      "Yes. Reach out from any live integration page — demand from design-partner teams drives our roadmap order.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast integrations",
    "github integration",
    "vercel integration",
    "linear integration",
    "sentry integration",
    "pagerduty integration",
    "stripe integration",
    "clerk integration",
    "posthog integration",
    "datadog integration",
    "engineering intelligence integrations",
  ],
  alternates: { canonical: PAGE_URL },
  openGraph: {
    title: "Lightfast Integrations",
    description: PAGE_DESCRIPTION,
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Integrations",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
  },
});

export default function IntegrationsIndexPage() {
  const pages = getIntegrationPages();

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "WebPage" as const,
        "@id": `${PAGE_URL}#webpage`,
        url: PAGE_URL,
        name: "Lightfast Integrations",
        description: PAGE_DESCRIPTION,
        isPartOf: { "@id": "https://lightfast.ai/#website" },
        publisher: { "@id": "https://lightfast.ai/#organization" },
